async function step1_download() {
  console.log("  [1/7] Telechargement...");
  rmDir(WORK); fs.mkdirSync(WORK, { recursive: true });
  const zipPath = path.join(WORK, "gh-pages.zip");
  await download("https://github.com/aveca/AcimCaisse/archive/refs/heads/gh-pages.zip", zipPath);
  exec("powershell -Command " + JSON.stringify("Expand-Archive -Path '" + zipPath + "' -DestinationPath '" + WORK + "' -Force"));
  fs.unlinkSync(zipPath);
  const srcDir = path.join(WORK, "AcimCaisse-gh-pages");
  if (!fs.existsSync(srcDir)) throw new Error("Fichiers non trouves");
  fs.mkdirSync(path.join(WORK, "app", "www"), { recursive: true });
  cpDir(srcDir, path.join(WORK, "app", "www"));
  console.log("  [1/7] OK");
}

function step2_patch() {
  console.log("  [2/7] Patches...");

  // index.html
  const idx = path.join(WORK, "app", "www", "index.html");
  let h = fs.readFileSync(idx, "utf8");
  h = h.replace('/AcimCaisse/"', '"/"');
  h = h.replace('href="/AcimCaisse/"', 'href="/"');
  h = h.replace('<script src="coi-serviceworker.js"></script>', "<!-- coi off -->");
  h = h.replace("<title>acim_caisse</title>", "<title>AcimCaisse</title>");
  h = h.replace('content="acim_caisse">', 'content="AcimCaisse">');
  // Ajouter le script shell (product_catalog.js supprime - panier unique)
  if (!h.includes('acim-shell.js')) {
    h = h.replace('</head>', '  <script src="acim-shell.js"></script>\n</head>');
  }
  // Ajouter le tracker UX pour analyse des parcours utilisateurs
  if (!h.includes('tracker.js')) {
    h = h.replace('</head>', '  <script src="tracker.js"></script>\n</head>');
  }
  fs.writeFileSync(idx, h);

  // main.dart.js — patch camera + modifier prix
  const dart = path.join(WORK, "app", "www", "main.dart.js");
  let js = fs.readFileSync(dart, "utf8");
  const labels = [
    ["Scanner un produit", "Rechercher un produit"],
    ["Scanner le QR", "Saisir le code"],
    ["Camera indisponible \\u2014 utilisez la recherche ci-dessous", "Recherchez un produit"],
    ["Camera indisponible", "Saisie manuelle"],
    ["Autorisez la camera ou saisissez le code-barres manuellement.\\n(", "Saisissez le code-barres manuellement. ("],
    ["Scannez ou recherchez un produit", "Recherchez un produit"],
    ["Scannez le QR du client ou collez son code.", "Collez le code du client."],
    ['"dev.steenbakker.mobile_scanner/scanner/method"', '"__off__"'],
    ['"dev.steenbakker.mobile_scanner/scanner/event"', '"__off_e__"'],
  ];
  for (const [old, rep] of labels) js = js.replace(old, rep);

  // Camera disable
  js += "\n;(function(){if(navigator.mediaDevices&&navigator.mediaDevices.getUserMedia){navigator.mediaDevices.getUserMedia=function(){return Promise.reject(new DOMException('Camera disabled','NotAllowedError'))};navigator.mediaDevices.enumerateDevices=function(){return Promise.resolve([])};}window.__acimNorm=function(b){return b?String(b).trim().toUpperCase().replace(/[\\s\\-\\.]/g,''):b};})();\n";

  // AcimCaisse patch — injection DANS l'IIFE dartProgram
  // CRITICAL: si l'injection existe déjà (gh-pages v16+), remplacer, pas doubler
  var existingStart = js.indexOf("// ─── AcimCaisse");
  var existingEnd = js.indexOf("// ─── FIN AcimCaisse ───");
  if (existingStart >= 0 && existingEnd >= 0 && existingEnd > existingStart) {
    // L'injection existe → remplacer par la nouvelle version
    js = js.substring(0, existingStart) + "\n// ─── AcimCaisse patch (inside IIFE) ───\n" + EMBED_ACIM_CAISSE + "\n// ─── FIN AcimCaisse ───\n" + js.substring(existingEnd + "// ─── FIN AcimCaisse ───".length);
    console.log("    -> Injection existante remplacée (pos " + existingStart + "-" + existingEnd + ")");
  } else if (existingStart >= 0) {
    // Injection existe mais sans marqueur FIN → chercher la fin du bloc IIFE
    console.log("    -> Injection existante détectée mais sans marqueur FIN, on garde le fichier intact");
    // Ne pas injecter — le gh-pages a déjà l'injection correcte
  } else {
    // Pas d'injection → injecter normalement
    var dmIdx = js.indexOf("dartMainRunner");
    if (dmIdx >= 0) {
      var afterDm = js.substring(dmIdx);
      var closeOffset = afterDm.indexOf("})()");
      if (closeOffset >= 0) {
        var absCloseIdx = dmIdx + closeOffset;
        js = js.substring(0, absCloseIdx) + "\n// ─── AcimCaisse patch (inside IIFE) ───\n" + EMBED_ACIM_CAISSE + "\n// ─── FIN AcimCaisse ───\n" + js.substring(absCloseIdx);
        console.log("    -> acim-hooks.js injecté dans l'IIFE (pos " + absCloseIdx + ")");
      } else {
        console.log("    -> ERREUR: })() non trouvé, patch ajouté à la fin");
        js += "\n// ─── AcimCaisse patch ───\n" + EMBED_ACIM_CAISSE + "\n// ─── FIN AcimCaisse ───\n";
      }
    } else {
      console.log("    -> ERREUR: dartMainRunner non trouvé, patch ajouté à la fin");
      js += "\n// ─── AcimCaisse patch ───\n" + EMBED_ACIM_CAISSE + "\n// ─── FIN AcimCaisse ───\n";
    }
  }

  fs.writeFileSync(dart, js);

  // Supprimer coi-serviceworker
  const coi = path.join(WORK, "app", "www", "coi-serviceworker.js");
  if (fs.existsSync(coi)) fs.unlinkSync(coi);

  // barcode.html (toujours embarqué via EMBED_BARCODE)
  fs.writeFileSync(path.join(WORK, "app", "www", "barcode.html"), EMBED_BARCODE);
  fs.writeFileSync(path.join(WORK, "app", "www", "customer-display.html"), EMBED_CUSTOMER_DISPLAY);
  // product_catalog.js SUPPRIME - panier unique (fix v29)
  fs.writeFileSync(path.join(WORK, "app", "www", "acim-shell.js"), ""/* merged into EMBED_ACIM_CAISSE */);
  console.log("    -> acim-shell.js ecrit");
  
  // Copier tracker.js pour le tracking UX
  const trackerSrc = path.join(__dirname, "tracker.js");
  const trackerDest = path.join(WORK, "app", "www", "tracker.js");
  if (fs.existsSync(trackerSrc)) {
    fs.copyFileSync(trackerSrc, trackerDest);
    console.log("    -> tracker.js copié");
  }
  
  // Copier le CSS de fix UX
  const cssSrc = path.join(__dirname, "acimcaisse-ux-fix.css");
  const cssDest = path.join(WORK, "app", "www", "acimcaisse-ux-fix.css");
  if (fs.existsSync(cssSrc)) {
    fs.copyFileSync(cssSrc, cssDest);
    console.log("    -> acimcaisse-ux-fix.css copié");
  }

  console.log("    -> barcode.html ecrit");

  // Remplacer pdf_extract.js par la version avec OCR
  fs.writeFileSync(path.join(WORK, "app", "www", "pdf_extract.js"), EMBED_PDF_EXTRACT);
  console.log("    -> pdf_extract.js (OCR v7 + pre-parse) ecrit")

  console.log("  [2/7] OK");
}

