  const menuLnk = path.join(process.env.APPDATA || "", "Microsoft", "Windows", "Start Menu", "Programs", "AcimCaisse.lnk");
  try { exec("powershell -Command " + JSON.stringify("$ws=New-Object -ComObject WScript.Shell;$s=$ws.CreateShortcut('" + menuLnk + "');$s.TargetPath='" + exe + "';$s.WorkingDirectory='" + path.dirname(exe) + "';$s.Save()")); } catch {}
  try { rmDir(WORK); console.log("    -> Temp nettoye"); } catch {}
